import org.junit.jupiter.api.Test;

class LmdbNativePathPlannerTest {

	private static final long PREDICATE = 101L;

	@Test
	void sameVariableAlgebraCompilesNatively() {
		LmdbNativeAggregatePlanner planner = planner();
		planner.slot("x");
		Var endpoint = Var.of("x");
		StatementPattern step = new StatementPattern(endpoint.clone(),
				Var.of("p", SimpleValueFactory.getInstance().createIRI("http://example.com/p"), true),
				endpoint.clone());
		ArbitraryLengthPath path = new ArbitraryLengthPath(endpoint.clone(), step, endpoint.clone(), 1L);

		assertThat(planner.compilePath(path)).isInstanceOf(PathPlan.class);
		assertThat(planner.compilePath(new ArbitraryLengthPath(endpoint.clone(), step.clone(), endpoint.clone(), 2L)))
				.isNull();
	}

	@Test
	void fanOutClosureFlipsPathCostAroundSelectiveSibling() {
		NativeLmdbQuerySource source = mock(NativeLmdbQuerySource.class);
		when(source.meanFanOut(PREDICATE, true)).thenReturn(OptionalDouble.of(2D));
		RowState row = boundStartRow(source);
		PathPlan path = path(10_000D);
		double selectiveSiblingCost = 32D;

		assertThat(path.estimate(row)).isEqualTo(16D).isLessThan(selectiveSiblingCost);
		when(source.meanFanOut(PREDICATE, true)).thenReturn(OptionalDouble.of(3D));
		assertThat(path.estimate(row)).isEqualTo(81D).isGreaterThan(selectiveSiblingCost);
		when(source.meanFanOut(PREDICATE, true)).thenReturn(OptionalDouble.of(20D));
		assertThat(path.estimate(row)).isEqualTo(10_000D);
	}

	@Test
	void backwardPathEstimateUsesObjectFanOut() {
		NativeLmdbQuerySource source = mock(NativeLmdbQuerySource.class);
		when(source.meanFanOut(PREDICATE, false)).thenReturn(OptionalDouble.of(2D));
		RowState row = boundTargetRow(source);

		assertThat(path(10_000D).estimate(row)).isEqualTo(16D);
	}

	@Test
	void memoizedReachabilityBecomesExactRepeatEstimate() {
		NativeLmdbQuerySource source = mock(NativeLmdbQuerySource.class);
		when(source.meanFanOut(PREDICATE, true)).thenReturn(OptionalDouble.of(3D));
		RowState row = boundStartRow(source);
		PathPlan path = path(10_000D);
		PathResultMemo memo = PathResultMemo.tryCreate(path, row);

		assertThat(memo).isNotNull();
		try {
			memo.store(path, PathCursor.MODE_FORWARD, 11L, new long[] { 12L, 13L, 14L }, 3);
			assertThat(path.estimate(row)).isEqualTo(3D);
		} finally {
			memo.close();
		}
		assertThat(path.estimate(row)).isEqualTo(81D);
	}

	private static LmdbNativeAggregatePlanner planner() {
		QueryEvaluationContext context = mock(QueryEvaluationContext.class);
		LmdbNativeEvaluationStrategy strategy = mock(LmdbNativeEvaluationStrategy.class);
		NativeLmdbQuerySource source = mock(NativeLmdbQuerySource.class);
		LmdbNativeValueCodec codec = new LmdbNativeValueCodec(mock(ValueStore.class));
		QueryValueEvaluationStep generic = bindings -> SimpleValueFactory.getInstance().createLiteral(false);

		when(strategy.getQueryEvaluationMode()).thenReturn(QueryEvaluationMode.STRICT);
		when(strategy.precompile(any(ValueExpr.class), any(QueryEvaluationContext.class))).thenReturn(generic);
		when(source.nativeValueCodec()).thenReturn(codec);
		when(source.idOf(any(Value.class))).thenReturn(PREDICATE);
		return new LmdbNativeAggregatePlanner(context, strategy, source);
	}

	private static RowState boundStartRow(NativeLmdbQuerySource source) {
		return row(source, 11L, NativeLmdbQuerySource.UNKNOWN_ID);
	}

	private static RowState boundTargetRow(NativeLmdbQuerySource source) {
		return row(source, NativeLmdbQuerySource.UNKNOWN_ID, 21L);
	}

	private static RowState row(NativeLmdbQuerySource source, long start, long target) {
		NativeSlotLayout layout = new NativeSlotLayout(Map.of("start", 0, "target", 1), null);
		layout.freeze(Arrays.asList("start", "target"));
		RowState row = new RowState(source, layout, new QueryBindingSet());
		Arrays.fill(row.slots, NativeLmdbQuerySource.UNKNOWN_ID);
		row.slots[0] = start;
		row.slots[1] = target;
		row.recomputeBoundMask();
		return row;
	}

	private static PathPlan path(double staticEstimate) {
		PatternPlan step = new PatternPlan(Term.slot(0), Term.constant(PREDICATE), Term.slot(1), Term.unbound(),
				ContextConstraint.UNRESTRICTED, false, staticEstimate);
		return new PathPlan(step, 0, NativeLmdbQuerySource.UNKNOWN_ID, 1, NativeLmdbQuerySource.UNKNOWN_ID,
				TripleIndex.SUBJ_IDX, TripleIndex.OBJ_IDX, false);
	}
}
